cardCss:
/*
 * STEAMPUNK
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Victorian brass machinery, riveted iron plates, exposed gears,
 *             wood panelling, warm gas-lamp light
 * Fonts     : Cinzel (front headers) · Courier Prime (back, telegraphic)
 * Palette   : brass #b8820a · iron #4a4540 · walnut #5c3010 · amber #f0b040
 *             patina green #4a7050 · off-white #f0e0c0
 * Front zones:
 *   Header  — riveted iron: feTurbulence/feDiffuseLighting (matte, raking)
 *   Porthole— brass ring:   feTurbulence/feSpecularLighting (tight highlight)
 *   Lower   — wood panel:   directional feTurbulence (baseFrequency 0.025 0.003)
 * Back      — parchment: aged paper texture, Courier Prime typewriter serif
 * Complexity note: three distinct material SVG filter zones on one card
 */

@import url("https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700&family=Courier+Prime:ital,wght@0,400;0,700;1,400&display=swap");

:root {
  --sp-brass:   #b8820a;
  --sp-iron:    #2a2520;
  --sp-walnut:  #5c3010;
  --sp-amber:   #f0b040;
  --sp-patina:  #4a7050;
  --sp-paper:   #f0e0c0;
  --sp-ink:     #2a1808;
}

html, body, div#qa { height: 100%; }

.card { background: var(--sp-iron); min-height: 100%; }

.off-screen { position: absolute; left: -9999px; }

.sp-card {
  min-height: 100%;
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
}

/* ── HEADER: IRON PLATE ── */
.sp-header {
  position: relative;
  background: var(--sp-iron);
  padding: 1rem 1.5rem 1.2rem;
  border-bottom: 3px solid var(--sp-brass);
  overflow: hidden;
}

.sp-iron-layer {
  position: absolute;
  inset: 0;
  background: #3a3530;
  filter: url(#sp-iron);
  pointer-events: none;
}

.sp-rivets {
  display: flex;
  justify-content: space-between;
  position: absolute;
  top: 0.45rem;
  left: 0.8rem;
  right: 0.8rem;
  pointer-events: none;
}

.sp-rivet {
  display: inline-block;
  width: 0.65rem;
  height: 0.65rem;
  background: radial-gradient(circle at 35% 35%, var(--sp-amber), var(--sp-brass) 60%, #6a4a08);
  border-radius: 50%;
  box-shadow: 0 1px 2px rgba(0,0,0,0.5);
}

.sp-prompt {
  font-family: "Cinzel", serif;
  font-size: 1.1rem;
  color: var(--sp-amber);
  letter-spacing: 0.12em;
  margin: 1.2rem 0 0;
  text-shadow: 0 1px 3px rgba(0,0,0,0.6);
  position: relative;
  z-index: 1;
}

/* ── PORTHOLE: BRASS RING ── */
.sp-porthole-zone {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #1a1512;
  padding: 1.2rem;
  flex: 1;
  min-height: 9rem;
}

.sp-brass-ring {
  position: absolute;
  inset: 0.6rem;
  border-radius: 50%;
  background: transparent;
  box-shadow:
    0 0 0 0.45rem var(--sp-brass),
    0 0 0 0.7rem #8a5c08,
    0 0 0 0.9rem var(--sp-brass),
    0 0 12px rgba(240,176,64,0.3);
  filter: url(#sp-brass);
  pointer-events: none;
  z-index: 1;
}

.sp-porthole-image {
  position: relative;
  z-index: 2;
  clip-path: circle(42%);
}

.sp-porthole-image img {
  max-width: 100%;
  max-height: 9rem;
  object-fit: cover;
  filter: sepia(0.3) contrast(1.1) brightness(0.85);
}

.sp-porthole-empty {
  font-size: 4rem;
  color: var(--sp-brass);
  opacity: 0.3;
  position: relative;
  z-index: 2;
}

/* ── LOWER PANEL: WOOD ── */
.sp-wood-panel {
  position: relative;
  background: var(--sp-walnut);
  border-top: 3px solid var(--sp-brass);
  overflow: hidden;
}

.sp-wood-layer {
  position: absolute;
  inset: 0;
  background: #7a4018;
  filter: url(#sp-wood);
  pointer-events: none;
  opacity: 0.85;
}

.sp-wood-content {
  position: relative;
  z-index: 1;
  padding: 1rem 1.5rem 1.2rem;
}

.sp-input-wrap input {
  font-family: "Courier Prime", monospace;
  font-size: 1.1rem;
  background: rgba(240,224,192,0.12);
  border: 1px solid var(--sp-brass);
  color: var(--sp-paper);
  width: 100%;
  padding: 0.4rem 0.6rem;
  letter-spacing: 0.05em;
  box-sizing: border-box;
}
.sp-input-wrap input:focus { outline: none; border-color: var(--sp-amber); background: rgba(240,224,192,0.2); }

.sp-hint-wrap { margin-top: 0.6rem; }
.sp-hint-link { font-family: "Courier Prime", monospace; font-size: 0.85rem; color: rgba(240,176,64,0.5); text-decoration: underline; }
.sp-hint-text { font-family: "Courier Prime", monospace; font-size: 0.9rem; color: var(--sp-paper); opacity: 0.7; margin-top: 0.3rem; }
.sp-audio { margin: 0 0 0.8rem; position: relative; z-index: 1; }

/* ── BACK: PARCHMENT ── */
.sp-back { background: var(--sp-paper); }

.sp-parchment-bg {
  position: absolute;
  inset: 0;
  background: var(--sp-paper);
  pointer-events: none;
}

.sp-back-content {
  position: relative;
  z-index: 1;
  padding: 2rem 2.5rem;
  width: 100%;
  box-sizing: border-box;
}

.sp-telegram-header {
  font-family: "Courier Prime", monospace;
  font-size: 0.7rem;
  color: var(--sp-ink);
  opacity: 0.45;
  letter-spacing: 0.25em;
  text-align: center;
  margin: 0 0 1.2rem;
}

.sp-telegram-footer {
  font-family: "Courier Prime", monospace;
  font-size: 0.65rem;
  color: var(--sp-ink);
  opacity: 0.35;
  letter-spacing: 0.2em;
  text-align: center;
  margin: 1.2rem 0 0;
}

.sp-term {
  font-family: "Courier Prime", monospace;
  font-size: 2.8rem;
  font-weight: 700;
  color: var(--sp-ink);
  margin: 0 0 0.5rem;
  letter-spacing: 0.05em;
  line-height: 1.2;
}

.sp-reading { font-family: "Courier Prime", monospace; font-size: 1.5rem; color: #6a3808; margin: 0 0 0.3rem; }
.sp-translation { font-family: "Courier Prime", monospace; font-size: 1.1rem; color: var(--sp-ink); opacity: 0.8; margin: 0 0 0.2rem; }
.sp-transliteration { font-family: "Courier Prime", monospace; font-size: 1rem; color: #6a3808; font-style: italic; opacity: 0.65; margin: 0; }
.sp-tags { font-family: "Courier Prime", monospace; font-size: 0.8rem; color: var(--sp-walnut); opacity: 0.5; margin: 0.5rem 0 0; }
.sp-rule { border: none; border-top: 1px solid rgba(42,24,8,0.25); margin: 0.8rem 0; }

.sp-picture img {
  max-width: 100%;
  max-height: 12rem;
  object-fit: contain;
  filter: sepia(0.5) contrast(1.1) brightness(0.9);
  margin-top: 0.8rem;
}

.append-play-btn-text a::after { content: "▶"; color: var(--sp-amber); }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2rem; cursor: pointer; }
